INSERT INTO public.messages (id, org_id, thread_id, author_id, contact_id, direction, body, sent_at) VALUES
  -- Thread 1: TechVista deal
  ('a8000000-0000-0000-0000-000000000001', 'a0000000-0000-0000-0000-000000000001', 'a7000000-0000-0000-0000-000000000001', 'b0000000-0000-0000-0000-000000000001', NULL,                                  'outbound', 'Hi Alice, following up on our call about the enterprise license. I have put together a proposal based on your requirements for 200 seats.', now() - interval '40 days'),
  ('a8000000-0000-0000-0000-000000000002', 'a0000000-0000-0000-0000-000000000001', 'a7000000-0000-0000-0000-000000000001', NULL,                                  'f2000000-0000-0000-0000-000000000001', 'inbound',  'Thanks Sarah. The proposal looks solid. Can we discuss volume discounts for the 200+ tier? Bob will join the next call as well.',             now() - interval '38 days'),
  ('a8000000-0000-0000-0000-000000000003', 'a0000000-0000-0000-0000-000000000001', 'a7000000-0000-0000-0000-000000000001', 'b0000000-0000-0000-0000-000000000001', NULL,                                  'outbound', 'Absolutely. I can offer 15% off at the 200-seat tier. Let me know when works for Bob and I will send a calendar invite.',                     now() - interval '37 days'),
  -- Thread 2: Orion deal
  ('a8000000-0000-0000-0000-000000000004', 'a0000000-0000-0000-0000-000000000001', 'a7000000-0000-0000-0000-000000000002', 'b0000000-0000-0000-0000-000000000001', NULL,                                  'outbound', 'Monica, great meeting last week. As discussed, here is the scope document for the platform expansion project.',                               now() - interval '55 days'),
  ('a8000000-0000-0000-0000-000000000005', 'a0000000-0000-0000-0000-000000000001', 'a7000000-0000-0000-0000-000000000002', NULL,                                  'f2000000-0000-0000-0000-000000000013', 'inbound',  'Sarah, this looks comprehensive. Our procurement team will review. Expect feedback by end of next week.',                                      now() - interval '52 days'),
  ('a8000000-0000-0000-0000-000000000006', 'a0000000-0000-0000-0000-000000000001', 'a7000000-0000-0000-0000-000000000002', NULL,                                  'f2000000-0000-0000-0000-000000000015', 'inbound',  'Hi Sarah, Olivia from procurement here. We have a few questions about the SLA terms in section 4. Can we schedule a call?',                   now() - interval '45 days'),
  -- Thread 3: CSV ticket
  ('a8000000-0000-0000-0000-000000000007', 'a0000000-0000-0000-0000-000000000001', 'a7000000-0000-0000-0000-000000000003', NULL,                                  'f2000000-0000-0000-0000-000000000001', 'inbound',  'When I try to export reports with more than 10k rows, the export fails with a server error. This is blocking our quarterly review.',           now() - interval '2 days'),
  ('a8000000-0000-0000-0000-000000000008', 'a0000000-0000-0000-0000-000000000001', 'a7000000-0000-0000-0000-000000000003', 'b0000000-0000-0000-0000-000000000005', NULL,                                  'outbound', 'Thanks for reporting this Alice. I have escalated to our engineering team. We are investigating the memory limits on our export worker.',      now() - interval '2 days'),
  ('a8000000-0000-0000-0000-000000000009', 'a0000000-0000-0000-0000-000000000001', 'a7000000-0000-0000-0000-000000000003', 'b0000000-0000-0000-0000-000000000004', NULL,                                  'internal', 'Confirmed: export worker runs out of memory at ~8k rows. Need to implement streaming export. Estimated fix: 2 days.',                         now() - interval '1 day'),
  -- Thread 4: GreenLeaf intro
  ('a8000000-0000-0000-0000-000000000010', 'a0000000-0000-0000-0000-000000000001', 'a7000000-0000-0000-0000-000000000004', 'b0000000-0000-0000-0000-000000000002', NULL,                                  'outbound', 'Clara, it was great meeting you at DataConf. As promised, here are the case studies from similar analytics companies using our platform.',     now() - interval '28 days'),
  ('a8000000-0000-0000-0000-000000000011', 'a0000000-0000-0000-0000-000000000001', 'a7000000-0000-0000-0000-000000000004', NULL,                                  'f2000000-0000-0000-0000-000000000003', 'inbound',  'Thanks Marcus. These are very relevant. I shared with Sam (our CEO) and he would like to set up a demo.',                                      now() - interval '25 days'),
  ('a8000000-0000-0000-0000-000000000012', 'a0000000-0000-0000-0000-000000000001', 'a7000000-0000-0000-0000-000000000004', 'b0000000-0000-0000-0000-000000000002', NULL,                                  'outbound', 'That is great to hear. How does next Tuesday at 2pm ET work? I will prepare a demo tailored to your data pipeline use case.',                 now() - interval '24 days'),
  -- Thread 5: SSO ticket
  ('a8000000-0000-0000-0000-000000000013', 'a0000000-0000-0000-0000-000000000001', 'a7000000-0000-0000-0000-000000000005', NULL,                                  'f2000000-0000-0000-0000-000000000007', 'inbound',  'Our SSO integration stopped working after we updated our IdP certificate. Getting SAML assertion timeout errors.',                             now() - interval '5 days'),
  ('a8000000-0000-0000-0000-000000000014', 'a0000000-0000-0000-0000-000000000001', 'a7000000-0000-0000-0000-000000000005', 'b0000000-0000-0000-0000-000000000005', NULL,                                  'outbound', 'Grace, this is likely a certificate mismatch. Can you upload the new IdP certificate in Settings > SSO > Certificates?',                      now() - interval '5 days'),
  ('a8000000-0000-0000-0000-000000000015', 'a0000000-0000-0000-0000-000000000001', 'a7000000-0000-0000-0000-000000000005', NULL,                                  'f2000000-0000-0000-0000-000000000007', 'inbound',  'That did it. We uploaded the new cert and SSO is working again. Thanks for the quick help.',                                                   now() - interval '4 days');

COMMIT;
